import { useState } from 'react';
import { Cpu } from 'lucide-react';

export function PioneerParticleCard() {
  const [coords, setCoords] = useState({ x: 0, y: 0 });
  const [hovered, setHovered] = useState(false);

  const handleMouseMove = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    setCoords({
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    });
  };

  return (
    <div 
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      className="relative w-full max-w-sm overflow-hidden rounded-2xl border border-white/10 bg-neutral-900/60 p-6 text-white backdrop-blur-xl shadow-2xl transition-all duration-300 hover:scale-[1.02] cursor-default"
    >
      {/* Glow highlight follow cursor */}
      {hovered && (
        <span 
          style={{
            left: coords.x,
            top: coords.y,
            transform: 'translate(-50%, -50%)',
            pointerEvents: 'none'
          }}
          className="absolute h-40 w-40 rounded-full bg-primary/20 blur-3xl transition-opacity duration-300"
        />
      )}

      <div className="relative z-10 flex flex-col gap-4">
        <div className="flex h-12 w-12 items-center justify-center rounded-xl bg-primary/10 border border-primary/20 text-primary">
          <Cpu className="h-6 w-6 animate-pulse" />
        </div>
        <div>
          <h4 className="text-lg font-bold tracking-tight text-white">Pioneer Processing Unit</h4>
          <p className="text-sm text-neutral-400 mt-1.5 leading-relaxed">
            Accelerate AI developer prompt cycles locally using native system threads.
          </p>
        </div>
      </div>
    </div>
  );
}

