          <span className="h-3.5 w-3.5 rounded-full bg-amber-400" />
          <span className="h-3.5 w-3.5 rounded-full bg-emerald-500 cursor-pointer" onClick={() => setIsMinimized(false)} />
        </div>
        <span className="text-xs font-mono text-muted-foreground">openblocks-terminal.sh</span>
